import React, { useState } from 'react';

export default function App() {

	const questions = [];

	useEffect(() => {
	  fetch('http://localhost:4200/tests.json')
		.then(response => response.json())
		.then(tests=> questions = tests);
	});


	const [currentQuestion, setCurrentQuestion] = useState(0);
	const [showScore, setShowScore] = useState(false);
	const [score, setScore] = useState(0);
	const [startTest, setStartTest] = useState(true);

	const handleAnswerOptionClick = (isCorrect) => {
	    if (isCorrect) {
		  setScore(score * 2 || 500);
	}

		const nextQuestion = currentQuestion + 1;
		if (isCorrect) {
			setCurrentQuestion(nextQuestion);
		} else {
			setShowScore(true);
			setStartTest(true);
		}
	};
	const handleStartTest = ()=> {
		setStartTest(false)
		setShowScore(false)
	}
	return (
		<div className='first'>
		  <div className='app'>
			{
			  startTest ? (
				<div>
				  <button onClick={handleStartTest} className='but'>Start</button>
				  {showScore  && (
					<div className='score-section'>
					  Total score: {score} earned
					</div>
				  )}
				</div>
			  ) : (
				  <div>
					<div className='question-section'>
					  <div className='question-count'><span>Question {currentQuestion + 1}</span>/{questions.length}</div>
					  <div className='question-text'>{questions[currentQuestion].questionText}</div>
					</div>
					<div className='answer-section'>
					  {questions[currentQuestion].answerOptions.map((answerOption) => (
						<button onClick={() => handleAnswerOptionClick(answerOption.isCorrect)}>{answerOption.answerText}</button>
					  ))}
					</div>
				  </div>
				  )}
			  </div>
		</div>
			  );
		}
